func (r *codeModifier) WriteHeader(code int) {
	if r.headerSent {
		return
	}

	if code >= 100 && code <= 199 {

		for k, v := range r.headerMap {
			r.responseWriter.Header()[k] = v
		}

		r.responseWriter.WriteHeader(code)
		return
	}

	for k, v := range r.headerMap {
		r.responseWriter.Header()[k] = v
	}
	r.responseWriter.WriteHeader(r.code)
	r.headerSent = true
}
